SELECT baseline.bldg_id, baseline."in.nhgis_tract_gisjoin", baseline.state, baseline.applicability, upgrade.applicability AS applicability_1 FROM (SELECT * FROM comstock_amy2018_r2_2025_md_by_state_and_county_parquet WHERE comstock_amy2018_r2_2025_md_by_state_and_county_parquet.upgrade = 0) AS baseline JOIN (SELECT * FROM comstock_amy2018_r2_2025_md_by_state_and_county_parquet WHERE comstock_amy2018_r2_2025_md_by_state_and_county_parquet.upgrade != 0) AS upgrade ON baseline.bldg_id = upgrade.bldg_id AND baseline."in.nhgis_tract_gisjoin" = upgrade."in.nhgis_tract_gisjoin" AND baseline.state = upgrade.state WHERE baseline.applicability = true AND upgrade.applicability = true AND upgrade.upgrade = 1 AND (baseline."out.electricity.total.energy_consumption..kwh" - upgrade."out.electricity.total.energy_consumption..kwh" >= 0.001 OR baseline."out.natural_gas.total.energy_consumption..kwh" - upgrade."out.natural_gas.total.energy_consumption..kwh" >= 0.001 OR baseline."out.other_fuel.total.energy_consumption..kwh" - upgrade."out.other_fuel.total.energy_consumption..kwh" >= 0.001 OR baseline."out.district_cooling.total.energy_consumption..kwh" - upgrade."out.district_cooling.total.energy_consumption..kwh" >= 0.001 OR baseline."out.district_heating.total.energy_consumption..kwh" - upgrade."out.district_heating.total.energy_consumption..kwh" >= 0.001)